import{_ as a,c as l,o as e,ae as i}from"./chunks/framework.CDjunVez.js";const c=JSON.parse('{"title":"6 個月衝破 10 億美元後，Anthropic 用首次併購買了什麼？","description":"一家高中輟學生創辦的開源專案，被估值 1,830 億美元的 AI 巨頭相中。這背後藏著 AI 編碼工具市場最關鍵的戰場。","frontmatter":{"title":"6 個月衝破 10 億美元後，Anthropic 用首次併購買了什麼？","description":"一家高中輟學生創辦的開源專案，被估值 1,830 億美元的 AI 巨頭相中。這背後藏著 AI 編碼工具市場最關鍵的戰場。","date":"2025-12-03T00:00:00.000Z","author":"Clement Tang","tags":["Anthropic","Bun","AI編碼","Claude","社群貼文"],"category":"articles","status":"published","lastModified":"2026-01-27T00:00:00.000Z"},"headers":[],"relativePath":"articles/2025-12-03-anthropic-acquires-bun-social.md","filePath":"articles/2025-12-03-anthropic-acquires-bun-social.md"}'),t={name:"articles/2025-12-03-anthropic-acquires-bun-social.md"};function o(n,r,s,p,u,h){return e(),l("div",null,[...r[0]||(r[0]=[i('<h1 id="_6-個月衝破-10-億美元後-anthropic-用首次併購買了什麼" tabindex="-1">6 個月衝破 10 億美元後，Anthropic 用首次併購買了什麼？ <a class="header-anchor" href="#_6-個月衝破-10-億美元後-anthropic-用首次併購買了什麼" aria-label="Permalink to &quot;6 個月衝破 10 億美元後，Anthropic 用首次併購買了什麼？&quot;">​</a></h1><blockquote><p>一家高中輟學生創辦的開源專案，被估值 1,830 億美元的 AI 巨頭相中。這背後藏著 AI 編碼工具市場最關鍵的戰場。</p></blockquote><hr><h2 id="高中輟學生-vs-ai-巨頭" tabindex="-1">高中輟學生 vs. AI 巨頭 <a class="header-anchor" href="#高中輟學生-vs-ai-巨頭" aria-label="Permalink to &quot;高中輟學生 vs. AI 巨頭&quot;">​</a></h2><p>Jarred Sumner 是個有趣的人。</p><p>高中輟學，自學程式設計，拿到 Peter Thiel 的獎學金，在 Stripe 待過兩次。2021 年，他開始寫一個 JavaScript runtime，目標很簡單：<strong>比 Node.js 快。</strong></p><p>四年後，他的專案 Bun 每月有 700 萬次下載，在 GitHub 上有 82,000 顆星。</p><p>然後，Anthropic 出手了。</p><p><strong>2025 年 12 月 2 日</strong>，Anthropic 宣布收購 Bun。這是這家估值 1,830 億美元的 AI 巨頭的首次併購。</p><p>收購金額沒有公開。但時機耐人尋味。</p><hr><h2 id="_6-個月-10-億美元-然後呢" tabindex="-1">6 個月，10 億美元，然後呢？ <a class="header-anchor" href="#_6-個月-10-億美元-然後呢" aria-label="Permalink to &quot;6 個月，10 億美元，然後呢？&quot;">​</a></h2><p>要理解這次併購，得先看 Claude Code 的瘋狂成長。</p><p><strong>2025 年 4 月</strong>，Claude Code 的年化營收是 1,750 萬美元。</p><p><strong>2025 年 7 月</strong>，衝到 4 億美元。</p><p><strong>2025 年 11 月</strong>，突破 10 億美元。</p><p><strong>從 4 月到 11 月，營收成長 57 倍。</strong></p><p>這種成長速度帶來一個問題：當你每週要處理 1.95 億行程式碼時，執行速度差 1 秒，累積起來就是巨大的成本和糟糕的用戶體驗。</p><p>Node.js 不夠快了。</p><p>Anthropic 需要更快的引擎。</p><hr><h2 id="_4-倍速度的誘惑" tabindex="-1">4 倍速度的誘惑 <a class="header-anchor" href="#_4-倍速度的誘惑" aria-label="Permalink to &quot;4 倍速度的誘惑&quot;">​</a></h2><p>Bun 到底有多快？</p><p><strong>HTTP 服務器測試：</strong></p><ul><li>Node.js：每秒 13,000 個請求</li><li>Bun：每秒 52,000 個請求</li><li><strong>快 4 倍</strong></li></ul><p><strong>CPU 密集任務：</strong></p><ul><li>Node.js：3,400 毫秒</li><li>Bun：1,700 毫秒</li><li><strong>快 2 倍</strong></li></ul><p><strong>套件安裝：</strong></p><ul><li>npm：基準速度</li><li>Bun：<strong>快 10-30 倍</strong></li></ul><p>這些數字在小規模應用中可能不明顯。但當你有 115,000 個開發者每週寫 1.95 億行程式碼，每一點性能提升都會被放大。</p><p><strong>4 倍的速度 = 4 倍的用戶體驗 = 可能 4 倍的成本節省。</strong></p><hr><h2 id="技術棧的掌控權" tabindex="-1">技術棧的掌控權 <a class="header-anchor" href="#技術棧的掌控權" aria-label="Permalink to &quot;技術棧的掌控權&quot;">​</a></h2><p>但速度只是表面原因。</p><p>真正的關鍵是 <strong>掌控權</strong>。</p><h3 id="當你依賴別人的技術" tabindex="-1">當你依賴別人的技術 <a class="header-anchor" href="#當你依賴別人的技術" aria-label="Permalink to &quot;當你依賴別人的技術&quot;">​</a></h3><p>在收購 Bun 之前,Claude Code 面臨的處境：</p><ul><li><strong>AI 模型</strong>：自己的（Claude 系列）✅</li><li><strong>編碼工具</strong>：自己的（Claude Code）✅</li><li><strong>執行引擎</strong>：別人的（Node.js）❌</li></ul><p>這意味著：</p><ul><li>想優化性能？等 Node.js 更新</li><li>想加新功能？看 Node.js 支不支援</li><li>想深度整合？受限於第三方 API</li></ul><h3 id="收購-bun-之後" tabindex="-1">收購 Bun 之後 <a class="header-anchor" href="#收購-bun-之後" aria-label="Permalink to &quot;收購 Bun 之後&quot;">​</a></h3><p>現在 Anthropic 可以：</p><ul><li><strong>客製化優化</strong>：針對 AI 編碼場景量身打造</li><li><strong>快速迭代</strong>：想加什麼功能自己決定</li><li><strong>深度整合</strong>：在 runtime 層級整合 AI 能力</li></ul><p>舉個例子：未來 Bun 可能直接內建 AI 輔助功能，在程式碼執行前就用 AI 優化。這是 Node.js 永遠做不到的。</p><p><strong>這就是技術棧掌控權的價值。</strong></p><hr><h2 id="三大競爭對手的壓力" tabindex="-1">三大競爭對手的壓力 <a class="header-anchor" href="#三大競爭對手的壓力" aria-label="Permalink to &quot;三大競爭對手的壓力&quot;">​</a></h2><p>AI 編碼工具市場在 2025 年已經是紅海。</p><p><strong>GitHub Copilot</strong>：微軟支持，市佔率第一，深度整合 VS Code</p><p><strong>Cursor</strong>：開發者最愛的 AI 程式碼編輯器，快速崛起</p><p><strong>Replit</strong>：完整的線上開發環境，從寫程式到部署一條龍</p><p>Claude Code 有什麼？</p><ul><li><strong>AI 能力</strong>：Claude 模型業界頂尖 ✅</li><li><strong>企業市場</strong>：Netflix、Spotify、Salesforce 都在用 ✅</li><li><strong>完整技術棧</strong>：現在有了 Bun ✅</li></ul><p><strong>競爭已經從「誰的 AI 更聰明」進化到「誰的完整體驗更好」。</strong></p><p>Anthropic 顯然看到了這一點。</p><hr><h2 id="開源的矛盾與機會" tabindex="-1">開源的矛盾與機會 <a class="header-anchor" href="#開源的矛盾與機會" aria-label="Permalink to &quot;開源的矛盾與機會&quot;">​</a></h2><p>Bun 的收購還有個有趣的角度：<strong>開源專案被大公司收購，到底是好是壞？</strong></p><h3 id="社群的擔憂" tabindex="-1">社群的擔憂 <a class="header-anchor" href="#社群的擔憂" aria-label="Permalink to &quot;社群的擔憂&quot;">​</a></h3><p><strong>會不會變調？</strong></p><ul><li>Bun 是開源專案，700 萬開發者在用</li><li>被 Anthropic 收購後，會不會只服務 Claude Code？</li><li>開源承諾還算數嗎？</li></ul><p><strong>Anthropic 的回應很明確：</strong></p><ul><li>Bun 繼續開源</li><li>MIT 授權不變</li><li>繼續投資讓 Bun 成為所有 JavaScript 開發者的首選</li></ul><h3 id="歷史參照" tabindex="-1">歷史參照 <a class="header-anchor" href="#歷史參照" aria-label="Permalink to &quot;歷史參照&quot;">​</a></h3><p><strong>成功案例：Microsoft 收購 GitHub</strong></p><ul><li>收購後繼續開源友善</li><li>投入更多資源</li><li>社群反而受益</li></ul><p><strong>失敗案例：某些被收購的開源專案</strong></p><ul><li>逐漸商業化</li><li>社群流失</li><li>最終消亡</li></ul><p>Bun 會是哪一種？時間會告訴我們答案。</p><hr><h2 id="從工具到平台的進化" tabindex="-1">從工具到平台的進化 <a class="header-anchor" href="#從工具到平台的進化" aria-label="Permalink to &quot;從工具到平台的進化&quot;">​</a></h2><p>這次併購最深層的意義是：<strong>AI 編碼工具正在從單一工具進化為完整平台。</strong></p><h3 id="第一代-ai-編碼工具-2023-2024" tabindex="-1">第一代 AI 編碼工具（2023-2024） <a class="header-anchor" href="#第一代-ai-編碼工具-2023-2024" aria-label="Permalink to &quot;第一代 AI 編碼工具（2023-2024）&quot;">​</a></h3><p><strong>競爭焦點：</strong></p><ul><li>誰的程式碼補全更準確？</li><li>誰能支援更多語言？</li><li>誰的 AI 更聰明？</li></ul><p><strong>本質：</strong> 輔助工具，幫開發者寫程式碼</p><h3 id="第二代-ai-編碼平台-2025" tabindex="-1">第二代 AI 編碼平台（2025-） <a class="header-anchor" href="#第二代-ai-編碼平台-2025" aria-label="Permalink to &quot;第二代 AI 編碼平台（2025-）&quot;">​</a></h3><p><strong>競爭焦點：</strong></p><ul><li>從寫程式到執行，誰的體驗更順暢？</li><li>誰能控制整個技術棧？</li><li>誰能提供企業級的完整解決方案？</li></ul><p><strong>本質：</strong> 完整平台，取代傳統開發流程</p><p><strong>Anthropic 的佈局：</strong></p><ul><li><strong>模型層</strong>：Claude 系列</li><li><strong>應用層</strong>：Claude Code、Claude Agent SDK</li><li><strong>基礎設施層</strong>：Bun（NEW）</li></ul><p>這是完整的技術棧。</p><hr><h2 id="三個被低估的細節" tabindex="-1">三個被低估的細節 <a class="header-anchor" href="#三個被低估的細節" aria-label="Permalink to &quot;三個被低估的細節&quot;">​</a></h2><h3 id="細節-1-bun-早就在用了" tabindex="-1">細節 1：Bun 早就在用了 <a class="header-anchor" href="#細節-1-bun-早就在用了" aria-label="Permalink to &quot;細節 1：Bun 早就在用了&quot;">​</a></h3><p>Anthropic 在公告中提到：「Bun 的合作對 Claude Code 團隊的快速執行至關重要，直接推動了 Claude Code native installer 的推出。」</p><p>這句話透露：<strong>Bun 不是被收購後才整合，而是早就在深度合作。</strong></p><p>收購只是把關係正式化。</p><h3 id="細節-2-jarred-sumner-的背景" tabindex="-1">細節 2：Jarred Sumner 的背景 <a class="header-anchor" href="#細節-2-jarred-sumner-的背景" aria-label="Permalink to &quot;細節 2：Jarred Sumner 的背景&quot;">​</a></h3><p>高中輟學，Thiel Fellowship，Stripe 兩次，用 Zig 語言寫 runtime。</p><p>這種創辦人是科技巨頭最想要的：</p><ul><li>深厚技術能力</li><li>執行力強</li><li>有清晰願景</li></ul><p><strong>人才可能比技術更重要。</strong></p><h3 id="細節-3-vercel-的尷尬" tabindex="-1">細節 3：Vercel 的尷尬 <a class="header-anchor" href="#細節-3-vercel-的尷尬" aria-label="Permalink to &quot;細節 3：Vercel 的尷尬&quot;">​</a></h3><p>Vercel 創辦人 Guillermo Rauch 是 Bun 的早期投資者。</p><p>Vercel 的 Next.js 是 JavaScript 生態系統的重要玩家。</p><p>現在 Bun 被 Anthropic 收購了,Vercel 的感覺可能很複雜：</p><ul><li>投資回報可能不錯 ✅</li><li>但 Bun 現在是「競爭對手的技術」❓</li></ul><p><strong>科技圈的關係總是這麼微妙。</strong></p><hr><h2 id="給創業者的三個啟示" tabindex="-1">給創業者的三個啟示 <a class="header-anchor" href="#給創業者的三個啟示" aria-label="Permalink to &quot;給創業者的三個啟示&quot;">​</a></h2><h3 id="啟示-1-開源專案可以是退出策略" tabindex="-1">啟示 1：開源專案可以是退出策略 <a class="header-anchor" href="#啟示-1-開源專案可以是退出策略" aria-label="Permalink to &quot;啟示 1：開源專案可以是退出策略&quot;">​</a></h3><p><strong>傳統開源創業路徑：</strong> 開源專案 → 商業版 → SaaS → 獲利 → IPO 或被收購</p><p><strong>Bun 的路徑：</strong> 開源專案 → 建立社群 → 被大公司收購 → 繼續開源</p><p>對於基礎設施類專案，第二種路徑可能更快、風險更低。</p><h3 id="啟示-2-性能永遠有價值" tabindex="-1">啟示 2：性能永遠有價值 <a class="header-anchor" href="#啟示-2-性能永遠有價值" aria-label="Permalink to &quot;啟示 2：性能永遠有價值&quot;">​</a></h3><p>在 AI、雲端、前端框架瘋狂發展的年代，很多人覺得「底層優化」已經不重要了。</p><p>Bun 證明：<strong>快永遠有價值。</strong></p><p>當別人都在談 AI 能力，Jarred Sumner 專注讓 JavaScript 跑得更快。結果被估值 1,830 億美元的公司收購。</p><h3 id="啟示-3-找到大客戶的痛點" tabindex="-1">啟示 3：找到大客戶的痛點 <a class="header-anchor" href="#啟示-3-找到大客戶的痛點" aria-label="Permalink to &quot;啟示 3：找到大客戶的痛點&quot;">​</a></h3><p>Claude Code 每週處理 1.95 億行程式碼。</p><p>對這種規模的客戶，Node.js 的性能問題被放大了。</p><p>Bun 剛好解決這個痛點。</p><p><strong>當你的技術能解決大客戶的關鍵痛點，價值會被顯著放大。</strong></p><hr><h2 id="競爭對手會怎麼做" tabindex="-1">競爭對手會怎麼做？ <a class="header-anchor" href="#競爭對手會怎麼做" aria-label="Permalink to &quot;競爭對手會怎麼做？&quot;">​</a></h2><p>Anthropic 收購 Bun 會引發連鎖反應嗎？</p><h3 id="microsoft-github-copilot" tabindex="-1">Microsoft / GitHub Copilot <a class="header-anchor" href="#microsoft-github-copilot" aria-label="Permalink to &quot;Microsoft / GitHub Copilot&quot;">​</a></h3><p>可能的動作：</p><ul><li>投資 Node.js 性能改進</li><li>收購其他開發工具</li><li>加強 VS Code 生態系統整合</li></ul><p>優勢：微軟有完整的開發者工具生態（VS Code、GitHub、Azure）</p><h3 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h3><p>可能的動作：</p><ul><li>尋求與其他 runtime 的合作</li><li>專注於差異化功能</li><li>或考慮類似的垂直整合</li></ul><p>挑戰：資源比不上大公司</p><h3 id="replit" tabindex="-1">Replit <a class="header-anchor" href="#replit" aria-label="Permalink to &quot;Replit&quot;">​</a></h3><p>可能的動作：</p><ul><li>強化自己的雲端執行環境</li><li>突出端到端的優勢</li><li>加快企業市場推進</li></ul><p>優勢：已經有完整的開發平台</p><p><strong>一個產業巨頭的策略轉變，往往會逼迫其他玩家跟進或尋找新定位。</strong></p><hr><h2 id="三個月後見真章" tabindex="-1">三個月後見真章 <a class="header-anchor" href="#三個月後見真章" aria-label="Permalink to &quot;三個月後見真章&quot;">​</a></h2><p>這次併購的成功與否，三個月內就會有初步答案。</p><h3 id="觀察指標-1-bun-的更新頻率" tabindex="-1">觀察指標 1：Bun 的更新頻率 <a class="header-anchor" href="#觀察指標-1-bun-的更新頻率" aria-label="Permalink to &quot;觀察指標 1：Bun 的更新頻率&quot;">​</a></h3><p>如果 Bun 的開發速度加快、新功能持續推出，代表整合順利。</p><p>如果更新變慢、社群貢獻減少，可能有問題。</p><h3 id="觀察指標-2-claude-code-的性能提升" tabindex="-1">觀察指標 2：Claude Code 的性能提升 <a class="header-anchor" href="#觀察指標-2-claude-code-的性能提升" aria-label="Permalink to &quot;觀察指標 2：Claude Code 的性能提升&quot;">​</a></h3><p>Anthropic 應該會在近期推出基於 Bun 優化的 Claude Code 版本。</p><p>性能提升多少？穩定性如何？用戶反應？</p><h3 id="觀察指標-3-開源社群的態度" tabindex="-1">觀察指標 3：開源社群的態度 <a class="header-anchor" href="#觀察指標-3-開源社群的態度" aria-label="Permalink to &quot;觀察指標 3：開源社群的態度&quot;">​</a></h3><p>GitHub stars 繼續成長嗎？ Issue 和 PR 保持活躍嗎？ 開發者還願意貢獻嗎？</p><p><strong>開源專案被收購後，社群的反應最誠實。</strong></p><hr><h2 id="寫在最後-速度即權力" tabindex="-1">寫在最後：速度即權力 <a class="header-anchor" href="#寫在最後-速度即權力" aria-label="Permalink to &quot;寫在最後：速度即權力&quot;">​</a></h2><p>從 Anthropic 併購 Bun 這件事，最核心的一個洞察是：</p><p><strong>在 AI 時代，速度不只是性能指標，更是戰略資產。</strong></p><p>Claude Code 每週處理 1.95 億行程式碼。當你達到這個規模：</p><ul><li>快 1 秒 = 節省數百萬美元成本</li><li>快 1 秒 = 更好的用戶體驗</li><li>快 1 秒 = 更多企業願意採用</li></ul><p><strong>速度創造複利效應。</strong></p><p>Jarred Sumner 用 4 年時間，把「讓 JavaScript 跑更快」這個簡單目標，變成了被 AI 巨頭收購的基礎設施。</p><p>這提醒我們：</p><ul><li>專注解決一個問題</li><li>把它做到極致</li><li>找到真正在乎的客戶</li></ul><p><strong>有時候，最簡單的價值主張，反而最有力量。</strong></p><p>對 Anthropic 來說，這是首次併購，也是宣示：我們要建立從模型到 runtime 的完整技術棧。</p><p>對 Bun 社群來說，這是機會也是考驗：能否在被大公司收購後，繼續保持開源活力？</p><p>對整個 AI 編碼市場來說，這是信號：<strong>競爭進入下半場，完整技術棧的爭奪開始了。</strong></p><p>接下來三到六個月，我們會看到這次併購的真正影響。</p><p>但可以確定的是：<strong>AI 編碼工具的戰爭，已經從 AI 能力延伸到底層基礎設施。</strong></p><p>掌控技術棧底層的公司，將在下一輪競爭中佔據優勢。</p><hr><h2 id="關鍵數據一覽" tabindex="-1">關鍵數據一覽 <a class="header-anchor" href="#關鍵數據一覽" aria-label="Permalink to &quot;關鍵數據一覽&quot;">​</a></h2><p><strong>Claude Code 成長軌跡：</strong></p><ul><li>2025 年 4 月：$17.5M ARR</li><li>2025 年 7 月：$400M ARR</li><li>2025 年 11 月：$1B run-rate revenue</li><li>成長倍數：57x（7 個月）</li><li>活躍開發者：115,000</li><li>每週處理程式碼：1.95 億行</li></ul><p><strong>Bun 的數據：</strong></p><ul><li>創立時間：2021 年</li><li>創辦人：Jarred Sumner（高中輟學,Thiel Fellowship）</li><li>月下載量：700 萬</li><li>GitHub stars：82,000</li><li>融資：$26M（Kleiner Perkins、Vercel 創辦人）</li><li>性能優勢：比 Node.js 快 2-4 倍</li></ul><p><strong>Anthropic 的佈局：</strong></p><ul><li>估值：$183B（2025 年 11 月）</li><li>2025 年預估營收：$3.3B</li><li>Claude Code 貢獻：$1B+</li><li>首次併購標的：Bun</li><li>戰略：垂直整合完整技術棧</li></ul><p><strong>AI 編碼市場（2025）：</strong></p><ul><li>主要玩家：GitHub Copilot、Cursor、Claude Code、Replit、v0.dev</li><li>競爭焦點：從 AI 能力轉向完整平台體驗</li><li>趨勢：垂直整合、企業市場、開源併購</li></ul><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><ol><li><a href="https://bun.com/blog/bun-joins-anthropic" target="_blank" rel="noreferrer">Bun is joining Anthropic | Bun Blog</a></li><li><a href="https://www.anthropic.com/news/anthropic-acquires-bun-as-claude-code-reaches-usd1b-milestone" target="_blank" rel="noreferrer">Anthropic acquires Bun as Claude Code reaches $1B milestone</a></li><li><a href="https://venturebeat.com/ai/anthropic-adds-usage-tracking-to-claude-code-as-enterprise-ai-spending-surges" target="_blank" rel="noreferrer">Claude Code revenue jumps 5.5x | VentureBeat</a></li><li><a href="https://strapi.io/blog/bun-vs-nodejs-performance-comparison-guide" target="_blank" rel="noreferrer">Bun vs Node.js 2025: Performance Comparison | Strapi</a></li><li><a href="https://www.infoworld.com/article/2338698/interview-with-jarred-sumner-buns-creator-talks-tech-funding-and-startups.html" target="_blank" rel="noreferrer">Jarred Sumner interview | InfoWorld</a></li><li><a href="https://news.ycombinator.com/item?id=46124267" target="_blank" rel="noreferrer">Anthropic acquires Bun | Hacker News</a></li></ol><hr><h2 id="更新記錄" tabindex="-1">更新記錄 <a class="header-anchor" href="#更新記錄" aria-label="Permalink to &quot;更新記錄&quot;">​</a></h2><ul><li><strong>2025-12-03：</strong> 建立社群版本文章，以商業周刊風格改寫 Anthropic 併購 Bun 分析</li></ul><hr>',177)])])}const g=a(t,[["render",o]]);export{c as __pageData,g as default};
